#' @keywords internal
.html_escape <- function(x) {
  x <- as.character(x)
  x <- gsub("&", "&amp;", x, fixed = TRUE)
  x <- gsub("<", "&lt;", x, fixed = TRUE)
  x <- gsub(">", "&gt;", x, fixed = TRUE)
  x <- gsub('"', "&quot;", x, fixed = TRUE)
  x
}

#' @keywords internal
.design_review_payload <- function(x, ...) {
  if (inherits(x, "DesignReviewSpec")) {
    return(x$to_list())
  }
  build_design_review_data(x, ...)$to_list()
}

#' Build standalone design-review HTML
#'
#' Creates a standalone, offline HTML/JavaScript review page from a design
#' review bundle or supported design object. The page is review-only: it renders
#' design artifacts and exports structured feedback JSON, but it does not run
#' workflow nodes, call LLM providers, or mutate saved R objects.
#'
#' @param x A [`DesignReviewSpec`] or any input accepted by
#'   [build_design_review_data()].
#' @param include_workflow Whether to render workflow graph information.
#' @param include_knowledge Whether to render narrative and graph knowledge.
#' @param include_memory_schema Whether to render memory/state/interface schema.
#' @param include_feedback_panel Whether to include the structured feedback
#'   form and JSON export controls.
#' @param self_contained Reserved for future asset handling. The current
#'   implementation is always self-contained and uses no remote resources.
#' @param title Optional page title.
#' @param graph_layout Workflow graph layout. `"grid"` preserves the original
#'   row/column placement; `"layered"` places nodes by DAG depth; `"swimlane"`
#'   groups nodes into responsibility lanes; `"process"` renders loop-heavy
#'   workflows as a vertical process spine with side branches.
#' @param edge_style Workflow edge routing style: `"straight"`, `"curved"`, or
#'   `"orthogonal"`.
#' @param node_color_theme Initial node-color theme: `"default"` uses
#'   human-gate, deterministic-automation, and external stochastic LLM
#'   categories. Parent nodes with nested workflows inherit the most
#'   restrictive descendant category in the default theme. `"subsystems"` uses
#'   subsystem tags such as `rwm`, `pg`, `ae`, `la`, and `iac` when available.
#' @param ... Additional arguments passed to [build_design_review_data()] when
#'   `x` is not already a [`DesignReviewSpec`].
#'
#' @return HTML string.
#' @export
design_review_html <- function(
  x,
  include_workflow = TRUE,
  include_knowledge = TRUE,
  include_memory_schema = TRUE,
  include_feedback_panel = TRUE,
  self_contained = TRUE,
  title = NULL,
  graph_layout = c("grid", "layered", "swimlane", "process"),
  edge_style = c("curved", "straight", "orthogonal"),
  node_color_theme = c("default", "subsystems"),
  ...
) {
  graph_layout <- match.arg(graph_layout)
  edge_style <- match.arg(edge_style)
  node_color_theme <- match.arg(node_color_theme)
  payload <- .design_review_payload(x, ...)
  validate_design_review_spec(payload)
  if (is.null(title)) {
    title <- paste("agentr design review:", payload$agent_name)
  }
  config <- list(
    include_workflow = isTRUE(include_workflow),
    include_knowledge = isTRUE(include_knowledge),
    include_memory_schema = isTRUE(include_memory_schema),
    include_feedback_panel = isTRUE(include_feedback_panel),
    graph_layout = graph_layout,
    edge_style = edge_style,
    node_color_theme = node_color_theme
  )
  payload_json <- jsonlite::toJSON(.preserve_spec_arrays(payload), auto_unbox = TRUE, null = "null", pretty = FALSE)
  config_json <- jsonlite::toJSON(config, auto_unbox = TRUE, null = "null", pretty = FALSE)

  paste(
    "<!doctype html>",
    '<html lang="en">',
    "<head>",
    '<meta charset="utf-8">',
    '<meta name="viewport" content="width=device-width, initial-scale=1">',
    paste0("<title>", .html_escape(title), "</title>"),
    "<style>",
    "body{margin:0;background:#f7f5ef;color:#1f2933;font-family:Georgia,'Times New Roman',serif;}",
    "header{padding:28px 34px;border-bottom:1px solid #c8c1b2;background:#efe8d8;}",
    "h1{margin:0 0 8px;font-size:28px;font-weight:600;} h2{font-size:19px;margin:0 0 12px;} h3{font-size:15px;margin:14px 0 6px;}",
    ".meta{font-size:13px;color:#5b6472}.wrap{display:grid;grid-template-columns:minmax(320px,1fr) 10px var(--side-width,360px);gap:0;padding:18px;align-items:start;--side-width:360px;}",
    ".main{display:grid;gap:18px;min-width:0}.panel{background:#fffdf7;border:1px solid #d7cebd;border-radius:10px;padding:16px;box-shadow:0 1px 2px rgba(0,0,0,.04);min-width:0}",
    ".splitter{position:relative;cursor:col-resize;user-select:none;touch-action:none;align-self:stretch;min-height:100%;margin:0 6px}.splitter::before{content:'';position:absolute;top:0;bottom:0;left:50%;width:2px;transform:translateX(-1px);background:linear-gradient(to bottom,#c5b79f,#9d8c73);border-radius:999px}.splitter:hover::before,.splitter.dragging::before{background:linear-gradient(to bottom,#8a7760,#5f5140)}",
    ".grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(230px,1fr));gap:10px}.card{border:1px solid #d8d2c4;border-radius:8px;padding:10px;background:#fff;overflow-wrap:anywhere}",
    ".card button{all:unset;cursor:pointer;display:block;width:100%;overflow-wrap:anywhere}.id{font:12px ui-monospace,SFMono-Regular,Menlo,monospace;color:#6b7280;overflow-wrap:anywhere}.label{font-weight:600;overflow-wrap:anywhere}.small{font-size:12px;color:#52606d;overflow-wrap:anywhere}",
    ".edge{font-size:13px;border-left:3px solid #8aa398;padding:7px 9px;background:#f8fbf8;margin:6px 0}.graph{min-height:170px;border:1px dashed #cfc7b8;border-radius:8px;background:#fbfaf6;margin-bottom:12px;overflow:auto;overscroll-behavior-x:contain}.graph-scroll{display:inline-block;min-width:max-content;padding:8px}.graph svg{display:block;max-width:none}.nested-wide .graph{min-height:260px}.notice{border-left:4px solid #b7791f;background:#fff7e6;padding:8px 10px;margin:0 0 10px 0;border-radius:6px;font-size:13px;color:#5f4300}.workflow-toolbar{display:flex;gap:12px;align-items:center;justify-content:space-between;flex-wrap:wrap;margin:0 0 10px}.workflow-toolbar .row-inline{display:flex;gap:8px;align-items:center;flex-wrap:wrap}.workflow-toolbar label{margin:0}.workflow-legend{display:flex;gap:8px;flex-wrap:wrap;margin:0 0 10px}.workflow-legend-item{display:inline-flex;align-items:center;gap:6px;font-size:12px;color:#52606d;background:#fff;border:1px solid #d8d2c4;border-radius:999px;padding:5px 9px}.workflow-swatch{width:12px;height:12px;border-radius:999px;display:inline-block;border:1px solid #607466}",
    "svg text{font-family:Georgia,'Times New Roman',serif}.feedback{position:sticky;top:12px;align-self:start}.row{display:grid;gap:5px;margin-bottom:9px}",
    "label{font-size:12px;font-weight:600;color:#384252}input,select,textarea{font:13px ui-sans-serif,system-ui,sans-serif;border:1px solid #b9c0c8;border-radius:6px;padding:7px;background:white}",
    "textarea{min-height:62px}.btns{display:flex;gap:8px;flex-wrap:wrap}.btn{border:1px solid #344e41;background:#344e41;color:#fff;border-radius:6px;padding:7px 10px;cursor:pointer;font-size:13px}",
    ".btn.secondary{background:#fff;color:#344e41}.feedback-item,.detail-box{font-size:12px;border:1px solid #d7cebd;border-radius:6px;padding:8px;margin-top:8px;background:#fff}.detail-box pre{max-height:170px}.detail-kv{display:grid;grid-template-columns:90px minmax(0,1fr);gap:4px 8px;font-size:12px;margin:6px 0}.detail-kv b{color:#384252}.feedback-section-gap{height:14px}",
    ".task-tabs{display:flex;gap:8px;flex-wrap:wrap;margin:8px 0 12px}.task-tab{border:1px solid #9b8f78;background:#fffdf7;color:#2f3a31;border-radius:999px;padding:7px 11px;cursor:pointer;font-size:13px}.task-tab.active{background:#344e41;color:#fff;border-color:#344e41}",
    "pre{white-space:pre-wrap;word-break:break-word;background:#20231f;color:#f4f1e8;border-radius:8px;padding:10px;font-size:12px;max-height:220px;overflow:auto}",
    "@media(max-width:900px){.wrap{grid-template-columns:1fr}.splitter{display:none}.feedback{position:static}}",
    "</style>",
    "</head>",
    "<body>",
    "<header>",
    paste0("<h1>", .html_escape(title), "</h1>"),
    '<div class="meta">Review-only artifact. Structured feedback must be imported back into R for validation before it affects any design object.</div>',
    "</header>",
    '<div class="wrap">',
    '<main class="main" id="main"></main>',
    '<div class="splitter" id="splitter" aria-hidden="true" title="Drag to resize panels"></div>',
    '<aside class="panel feedback" id="feedbackPanel"></aside>',
    "</div>",
    '<script id="agentr-review-data" type="application/json">',
    as.character(payload_json),
    "</script>",
    '<script id="agentr-review-config" type="application/json">',
    as.character(config_json),
    "</script>",
    "<script>",
    "const data=JSON.parse(document.getElementById('agentr-review-data').textContent);",
    "const config=JSON.parse(document.getElementById('agentr-review-config').textContent);",
    "const feedback=[];",
    "const main=document.getElementById('main'); const panel=document.getElementById('feedbackPanel'); const wrap=document.querySelector('.wrap'); const splitter=document.getElementById('splitter');",
    "const subsystemPalette={rwm:{fill:'#E0F2FE',stroke:'#0369A1',label:'RWM'},pg:{fill:'#DCFCE7',stroke:'#15803D',label:'PG'},ae:{fill:'#FDE68A',stroke:'#B45309',label:'AE'},la:{fill:'#FCE7F3',stroke:'#BE185D',label:'LA'},iac:{fill:'#EDE9FE',stroke:'#6D28D9',label:'IAC'}};",
    "let currentWorkflowGraphEl=null; let currentTaskPreviewId=null;",
    "function esc(x){return String(x??'').replace(/[&<>\"']/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','\"':'&quot;',\"'\":'&#39;'}[m]));}",
    "function val(x){return x===null||x===undefined||x===''?'':x;}",
    "function section(title,id){const s=document.createElement('section');s.className='panel';s.id=id;s.innerHTML='<h2>'+esc(title)+'</h2>';main.appendChild(s);return s;}",
    "function selectTarget(target,targetId,field){if(!config.include_feedback_panel)return;document.getElementById('fb_target').value=target;document.getElementById('fb_target_id').value=targetId||'';document.getElementById('fb_field').value=field||target;}",
    "function jsonBlock(x){if(x===null||x===undefined)return'<pre>null</pre>';return'<pre>'+esc(JSON.stringify(x,null,2))+'</pre>';}",
    "function arrayValue(x){return Array.isArray(x)?x:(x===null||x===undefined||x===''?[]:[x]);}",
    "function knowledgeRefs(x){return arrayValue(x).map(String);}",
    "function normalizeSubsystemKey(x){x=String(x||'').toLowerCase();return['rwm','pg','ae','la','iac'].includes(x)?x:'';}",
    "function nodeSubsystem(id){const subsystemMap=(data.workflow_graph.metadata||{}).node_subsystems||(data.metadata||{}).node_subsystems||{};const labels=subsystemMap[id];const normalized=arrayValue(labels).map(normalizeSubsystemKey).filter(Boolean);return normalized.length?normalized[0]:'';}",
    "function nodeColorTheme(){const sel=document.getElementById('workflow-theme-select');return sel?sel.value:(config.node_color_theme||'default');}",
    "function baseWorkflowCategory(n){if(n.human_required)return{key:'human',fill:'#FFF1D6',stroke:'#B45309',label:'Human gate'};if(String(val(n.automation_status))==='llm_assisted'||String(val(n.automation_status))==='external_llm')return{key:'external',fill:'#E9E4FB',stroke:'#6D28D9',label:'External stochastic LLM'};return{key:'deterministic',fill:'#E8F3EE',stroke:'#607466',label:'Deterministic automation'};}",
    "function categoryPriority(key){return key==='human'?3:key==='external'?2:1;}",
    "function effectiveWorkflowCategory(n){const base=baseWorkflowCategory(n);let best=base;const nested=(n&&n.nested_workflow&&n.nested_workflow.nodes)||[];nested.forEach(child=>{const childCategory=effectiveWorkflowCategory(child);if(categoryPriority(childCategory.key)>categoryPriority(best.key))best=childCategory;});return best;}",
    "function nodeVisual(n){if(nodeColorTheme()==='subsystems'){const key=nodeSubsystem(n.id);if(key&&subsystemPalette[key])return subsystemPalette[key];return{fill:'#EEF2F7',stroke:'#7B8794',label:'Unlabeled'};}return effectiveWorkflowCategory(n);}",
    "function hasNestedWorkflow(n){return!!(n&&n.nested_workflow&&Array.isArray(n.nested_workflow.nodes)&&n.nested_workflow.nodes.length);}",
    "function workflowNodeById(id){return(data.workflow_graph.nodes||[]).find(n=>n.id===id);}",
    "function workflowEdgeByIndex(index,edges){return((edges||[])[index])||null;}",
    "function renderDetailObject(n,note){const box=document.getElementById('node_detail');if(!box)return;const refs=knowledgeRefs(n.knowledge_refs).join(', ');const hasNested=n.nested_workflow&&n.nested_workflow.nodes;const subsystem=nodeSubsystem(n.id);const category=nodeColorTheme()==='subsystems'?(subsystemPalette[subsystem]||{label:'Unlabeled'}):effectiveWorkflowCategory(n);box.innerHTML=`<div class='detail-box'><div class='id'>${esc(n.id)}</div><div class='label'>${esc(n.label)}</div>${note?`<div class='small'>${esc(note)}</div>`:''}<div class='detail-kv'><b>Rule</b><span>${esc(val(n.rule_spec))}</span><b>Owner</b><span>${esc(val(n.owner))}</span><b>Automation</b><span>${esc(val(n.automation_status))}</span><b>Human gate</b><span>${esc(n.human_required)}</span><b>Category</b><span>${esc(category.label||'')}</span><b>Subsystem</b><span>${esc(subsystem||'')}</span><b>Hint</b><span>${esc(val(n.implementation_hint))}</span><b>Knowledge</b><span>${esc(refs)}</span><b>Subworkflow</b><span>${esc(val(n.subworkflow_ref))}</span></div><h3>Input schema</h3>${jsonBlock(n.input_schema||{})}<h3>Output schema</h3>${jsonBlock(n.output_schema||{})}${hasNested?'<div class=\"small\">Nested workflow is available through the task tabs in the main column.</div>':''}</div>`;}",
    "function renderNodeDetail(id){const n=workflowNodeById(id);if(!n){renderDetailObject({id:'',label:'Click a workflow node or edge to inspect its details.'},'');return;}renderDetailObject(n,'Top-level workflow node');if(n.nested_workflow&&n.nested_workflow.nodes)renderTaskPreview(id);}",
    "function renderNestedNodeDetail(parentId,nodeId){const parent=workflowNodeById(parentId);const n=parent&&parent.nested_workflow&&parent.nested_workflow.nodes?(parent.nested_workflow.nodes||[]).find(x=>x.id===nodeId):null;if(!n)return;renderDetailObject(n,'Nested node inside '+parentId);selectTarget('workflow_node',parentId+'::'+nodeId,'workflow.nodes.'+parentId+'.nested_workflow.nodes.'+nodeId);}",
    "function renderEdgeDetailObject(e,note,nodes){const box=document.getElementById('node_detail');if(!box)return;const a=(nodes||[]).find(n=>n.id===e.from)||workflowNodeById(e.from)||{};const b=(nodes||[]).find(n=>n.id===e.to)||workflowNodeById(e.to)||{};box.innerHTML=`<div class='detail-box'><div class='id'>${esc(e.from)} -> ${esc(e.to)}</div><div class='label'>${esc(val(e.relation)||'depends_on')}</div>${note?`<div class='small'>${esc(note)}</div>`:''}<div class='detail-kv'><b>From id</b><span>${esc(e.from)}</span><b>From label</b><span>${esc(val(a.label))}</span><b>To id</b><span>${esc(e.to)}</span><b>To label</b><span>${esc(val(b.label))}</span><b>Relation</b><span>${esc(val(e.relation)||'depends_on')}</span><b>Condition</b><span>${esc(val(e.condition))}</span><b>Branch group</b><span>${esc(val(e.branch_group))}</span><b>Mutually exclusive</b><span>${esc(val(e.mutually_exclusive))}</span><b>Confidence</b><span>${esc(val(e.confidence))}</span><b>Notes</b><span>${esc(val(e.notes))}</span></div></div>`;}",
    "function renderWorkflowEdge(index,edges){const e=workflowEdgeByIndex(index,edges);if(!e)return;renderEdgeDetailObject(e,'Workflow edge',data.workflow_graph.nodes||[]);selectTarget('workflow_edge',e.from+'->'+e.to,'workflow.edges');}",
    "function selectWorkflowNode(id){renderNodeDetail(id);selectTarget('workflow_node',id,'workflow.nodes.'+id);}",
    "function wrapSvgText(text,maxChars=22){const words=String(text??'').split(/\\s+/).filter(Boolean);const lines=[];let line='';const pushLong=w=>{while(w.length>maxChars){lines.push(w.slice(0,maxChars));w=w.slice(maxChars);}return w;};words.forEach(word=>{word=pushLong(word);if(!word)return;if(!line){line=word;}else if((line+' '+word).length<=maxChars){line+=' '+word;}else{lines.push(line);line=word;}});if(line)lines.push(line);return lines.length?lines:[''];}",
    "function svgTspans(lines,x,startDy,lineHeight){return lines.map((line,i)=>`<tspan x='${x}' dy='${i===0?startDy:lineHeight}'>${esc(line)}</tspan>`).join('');}",
    "function prepareWorkflowNodes(nodes){nodes.forEach(n=>{n._lines=wrapSvgText(n.label,24);n._h=Math.max(54,26+n._lines.length*15);});}",
    "function hasBackwardEdges(nodes,edges){const order=Object.fromEntries((nodes||[]).map((n,i)=>[n.id,i]));return(edges||[]).some(e=>Number.isFinite(order[e.from])&&Number.isFinite(order[e.to])&&order[e.to]<=order[e.from]);}",
    "function layoutWorkflowGrid(nodes,opt){const rows=Math.max(1,Math.ceil(nodes.length/3));nodes.forEach((n,i)=>{n._row=Math.floor(i/3);n._x=opt.left+(i%3)*opt.colGap;});const rowHeights=[];for(let r=0;r<rows;r++){const rowNodes=nodes.filter(n=>n._row===r);rowHeights[r]=rowNodes.length?Math.max(...rowNodes.map(n=>n._h)):62;}let cursor=opt.top;for(let r=0;r<rows;r++){nodes.filter(n=>n._row===r).forEach(n=>{n._y=cursor;});cursor+=rowHeights[r]+opt.rowGap;}return Math.max(190,cursor-opt.rowGap+opt.top);}",
    "function dagDepth(nodes,edges){const byId=Object.fromEntries(nodes.map(n=>[n.id,n]));const order=Object.fromEntries(nodes.map((n,i)=>[n.id,i]));const indeg=Object.fromEntries(nodes.map(n=>[n.id,0]));edges.forEach(e=>{if(byId[e.from]&&byId[e.to])indeg[e.to]=(indeg[e.to]||0)+1;});const q=nodes.filter(n=>(indeg[n.id]||0)===0).map(n=>n.id);const depth=Object.fromEntries(nodes.map(n=>[n.id,0]));const processed=new Set();let guard=0;while(q.length&&guard++<nodes.length*nodes.length){const id=q.shift();processed.add(id);edges.filter(e=>e.from===id&&byId[e.to]).forEach(e=>{depth[e.to]=Math.max(depth[e.to]||0,(depth[id]||0)+1);indeg[e.to]-=1;if(indeg[e.to]===0)q.push(e.to);});}if(processed.size<nodes.length){nodes.forEach(n=>{depth[n.id]=0;});for(let pass=0;pass<nodes.length;pass++){let changed=false;edges.forEach(e=>{if(byId[e.from]&&byId[e.to]&&order[e.to]>order[e.from]){const d=(depth[e.from]||0)+1;if(d>(depth[e.to]||0)){depth[e.to]=d;changed=true;}}});if(!changed)break;}}return depth;}",
    "function layoutWorkflowLayered(nodes,edges,opt){const depth=dagDepth(nodes,edges);nodes.forEach((n,i)=>{n._depth=depth[n.id]??i;n._col=n._depth;n._row=0;});const maxDepth=nodes.length?Math.max(...nodes.map(n=>n._depth)):0;const maxCols=4;if(maxDepth>=maxCols){nodes.forEach(n=>{n._band=Math.floor(n._depth/maxCols);n._col=n._depth%maxCols;});const bands=[...new Set(nodes.map(n=>n._band))].sort((a,b)=>a-b);let y=opt.top;bands.forEach(band=>{const bandNodes=nodes.filter(n=>n._band===band);const groups={};bandNodes.forEach(n=>{const k=String(n._col);if(!groups[k])groups[k]=[];groups[k].push(n);});let bandHeight=70;Object.keys(groups).forEach(k=>{groups[k].sort((a,b)=>String(a.id).localeCompare(String(b.id)));const stackHeight=groups[k].reduce((sum,n)=>sum+n._h+opt.rowGap/2,0);bandHeight=Math.max(bandHeight,stackHeight);});Object.keys(groups).forEach(k=>{let stackY=y;groups[k].forEach((n,ri)=>{n._x=opt.left+n._col*opt.colGap;n._y=stackY;n._row=ri;stackY+=n._h+opt.rowGap/2;});});y+=bandHeight+opt.rowGap*2;});return Math.max(190,y-opt.rowGap);}const cols=[...new Set(nodes.map(n=>n._col))].sort((a,b)=>a-b);let maxBottom=0;cols.forEach((col,ci)=>{const colNodes=nodes.filter(n=>n._col===col);let y=opt.top;colNodes.forEach((n,ri)=>{n._x=opt.left+ci*opt.colGap;n._y=y;n._row=ri;y+=n._h+opt.rowGap;maxBottom=Math.max(maxBottom,n._y+n._h+opt.top);});});return Math.max(190,maxBottom);}",
    "function layoutWorkflowProcess(nodes,edges,opt){const order=Object.fromEntries(nodes.map((n,i)=>[n.id,i]));const byId=Object.fromEntries(nodes.map(n=>[n.id,n]));const out=Object.fromEntries(nodes.map(n=>[n.id,0]));edges.forEach(e=>{if(Number.isFinite(order[e.from])&&Number.isFinite(order[e.to]))out[e.from]=(out[e.from]||0)+1;});const branchBySource={};edges.forEach(e=>{if(Number.isFinite(order[e.from])&&Number.isFinite(order[e.to])&&isBranchEdge(e)){if(!branchBySource[e.from])branchBySource[e.from]=[];branchBySource[e.from].push(e);}});Object.keys(branchBySource).forEach(src=>{if(branchBySource[src].length<2)delete branchBySource[src];});const branchIds=new Set();Object.values(branchBySource).forEach(group=>group.forEach(e=>branchIds.add(e.to)));const decisionJoinIds=new Set();const decisionJoinBySource={};Object.entries(branchBySource).forEach(([src,group])=>{const downstream=group.map(e=>new Set(edges.filter(edge=>edge.from===e.to).map(edge=>edge.to)));if(!downstream.length)return;const common=[...downstream[0]].filter(id=>downstream.every(set=>set.has(id)));if(common.length){const joinId=common.sort((a,b)=>(order[a]??9999)-(order[b]??9999))[0];decisionJoinBySource[src]=joinId;decisionJoinIds.add(joinId);}});edges.forEach(e=>{if(Number.isFinite(order[e.from])&&Number.isFinite(order[e.to])&&order[e.to]>order[e.from]+1&&(out[e.to]||0)===0)branchIds.add(e.to);});nodes.forEach((n,i)=>{n._processIndex=i;n._depth=i;n._processBranch=branchIds.has(n.id);n._processBranchSource='';n._decisionJoin=decisionJoinIds.has(n.id);n._processBranchLane=null;delete n._x;delete n._y;});let y=opt.top;const spineX=opt.left+120;const branchGap=Math.max(opt.colGap,320);nodes.forEach(n=>{if(n._processBranch)return;if(n._decisionJoin&&Number.isFinite(n._y)){y=Math.max(y,n._y+n._h+opt.rowGap);return;}n._x=spineX;n._y=y;y+=n._h+opt.rowGap;const group=branchBySource[n.id];if(group){const targets=group.map(e=>byId[e.to]).filter(Boolean);const count=targets.length;const startX=n._x-((count-1)*branchGap)/2;const branchY=n._y+n._h+opt.rowGap;let maxBranchBottom=n._y+n._h;targets.forEach((b,idx)=>{b._processBranch=true;b._processBranchSource=n.id;b._x=startX+idx*branchGap;b._y=branchY;b._processBranchLane=idx;maxBranchBottom=Math.max(maxBranchBottom,b._y+b._h);});const join=byId[decisionJoinBySource[n.id]];if(join&&!branchIds.has(join.id)){join._decisionJoin=true;join._x=spineX;join._y=maxBranchBottom+opt.rowGap;y=Math.max(y,join._y+join._h+opt.rowGap);}}});const branchCount={};edges.forEach(e=>{const a=byId[e.from],b=byId[e.to];if(a&&b&&b._processBranch&&!Number.isFinite(b._y)){branchCount[a.id]=(branchCount[a.id]||0)+1;b._processBranchSource=a.id;b._x=spineX+branchGap;b._y=a._y+(branchCount[a.id]-1)*(b._h+opt.rowGap/2);}});nodes.filter(n=>n._processBranch&&!Number.isFinite(n._y)).forEach(n=>{n._x=spineX+branchGap;n._y=y;y+=n._h+opt.rowGap;});const minNodeX=nodes.length?Math.min(...nodes.map(n=>n._x)):spineX;edges.forEach(e=>{const a=byId[e.from],b=byId[e.to];if(a&&b&&a._processBranch&&!b._processBranch){e._branchRejoin=true;e._branchRejoinSide=a._x<b._x?'left':'right';e._branchRailX=e._branchRejoinSide==='left'?Math.min(a._x,b._x)-58:Math.max(a._x+opt.nodeW,b._x+opt.nodeW)+58;}});const feedbackEdges=edges.filter(e=>{const a=byId[e.from],b=byId[e.to];return a&&b&&Number.isFinite(a._processIndex)&&Number.isFinite(b._processIndex)&&b._processIndex<a._processIndex;}).sort((e1,e2)=>((order[e2.from]-order[e2.to])-(order[e1.from]-order[e1.to])));feedbackEdges.forEach((e,idx)=>{e._feedbackRailX=minNodeX-140-idx*56;});const maxBottom=nodes.length?Math.max(...nodes.map(n=>n._y+n._h+opt.top)):190;return Math.max(190,maxBottom);}",
    "function laneLabel(n){const owner=val(n.owner);if(owner)return'owner: '+owner;const automation=val(n.automation_status);if(automation)return'automation: '+automation;return n.human_required?'human gate':'no human gate';}",
    "function layoutWorkflowSwimlane(nodes,edges,opt){const depth=dagDepth(nodes,edges);nodes.forEach((n,i)=>{n._lane=laneLabel(n);n._col=depth[n.id]??i;});const lanes=[];nodes.forEach(n=>{if(!lanes.includes(n._lane))lanes.push(n._lane);});let y=opt.top;lanes.forEach(lane=>{const laneNodes=nodes.filter(n=>n._lane===lane).sort((a,b)=>(a._col-b._col)||String(a.id).localeCompare(String(b.id)));const colGroups={};laneNodes.forEach(n=>{const k=String(n._col);if(!colGroups[k])colGroups[k]=[];colGroups[k].push(n);});let laneHeight=92;Object.keys(colGroups).forEach(k=>{const stack=colGroups[k];const stackHeight=24+stack.reduce((sum,n)=>sum+n._h+opt.rowGap/2,0);laneHeight=Math.max(laneHeight,stackHeight);});Object.keys(colGroups).forEach(k=>{let stackY=y+24;colGroups[k].forEach(n=>{n._x=opt.left+150+n._col*opt.colGap;n._y=stackY;stackY+=n._h+opt.rowGap/2;});});laneNodes.forEach(n=>{n._laneY=y;n._laneH=laneHeight;});y+=laneHeight+opt.rowGap;});return Math.max(190,y-opt.rowGap+opt.top);}",
    "function isBranchEdge(e){return String(val(e.relation)).includes('branch')||!!val(e.condition)||!!val(e.branch_group)||e.mutually_exclusive===true;}",
    "function edgeVisual(e){return isBranchEdge(e)?{stroke:'#B45309',dash:'6 4',marker:'url(#arrow-branch)',labelFill:'#FFF7E6',labelStroke:'#D69E2E'}:{stroke:'#6b7280',dash:'',marker:'url(#arrow)',labelFill:'#fffdf7',labelStroke:'#d7cebd'};}",
    "function edgeLabel(e){if(val(e.condition))return String(e.condition);if(isBranchEdge(e)&&val(e.relation))return String(e.relation);return'';}",
    "function edgeLabelPosition(a,b,e={}){if(isBranchEdge(e)&&b._processBranch){return{x:b._x+90,y:Math.min(a._y+a._h+22,b._y-10)};}return{x:(a._x+b._x)/2+90,y:(a._cy+b._cy)/2-6};}",
    "function edgeAnchors(a,b,nodeW){const acx=a._x+nodeW/2,bcx=b._x+nodeW/2,dy=b._cy-a._cy,dx=bcx-acx;if(Math.abs(dx)<nodeW*0.35&&Math.abs(dy)>8){if(dy>=0)return{sx:acx,sy:a._y+a._h,tx:bcx,ty:b._y,axis:'vertical'};return{sx:acx,sy:a._y,tx:bcx,ty:b._y+b._h,axis:'vertical'};}if(dx>=0)return{sx:a._x+nodeW,sy:a._cy,tx:b._x,ty:b._cy,axis:'horizontal'};return{sx:a._x,sy:a._cy,tx:b._x+nodeW,ty:b._cy,axis:'horizontal'};}",
    "function edgePath(a,b,nodeW,style,index,e={}){const p=edgeAnchors(a,b,nodeW);const sx=p.sx,sy=p.sy,tx=p.tx,ty=p.ty;const offset=((index%5)-2)*10;const feedback=(Number.isFinite(a._processIndex)&&Number.isFinite(b._processIndex)&&b._processIndex<a._processIndex)||(Number.isFinite(a._depth)&&Number.isFinite(b._depth)&&b._depth<a._depth);if(style==='straight')return`M ${sx} ${sy} L ${tx} ${ty}`;if(style==='orthogonal'){if(isBranchEdge(e)&&b._processBranch&&!e._branchRejoin){const left=b._x<a._x;const startX=left?a._x:a._x+nodeW;const startY=a._cy;const endX=b._x+nodeW/2;const endY=b._y;return`M ${startX} ${startY} L ${endX} ${startY} L ${endX} ${endY}`;}if(e._branchRejoin){const left=e._branchRejoinSide==='left';const railX=Number.isFinite(e._branchRailX)?e._branchRailX:(left?Math.min(a._x,b._x)-58:Math.max(a._x+nodeW,b._x+nodeW)+58);const startX=left?a._x:a._x+nodeW;const endX=left?b._x:b._x+nodeW;return`M ${startX} ${a._cy} L ${railX} ${a._cy} L ${railX} ${b._cy} L ${endX} ${b._cy}`;}if(feedback){const sameProcessColumn=Number.isFinite(a._processIndex)&&Number.isFinite(b._processIndex)&&Math.abs(a._x-b._x)<2;const startX=sameProcessColumn?a._x:a._x+nodeW/2;const endX=sameProcessColumn?b._x:b._x+nodeW/2;const startY=sameProcessColumn?a._cy:(b._y<a._y?a._y:a._y+a._h);const endY=sameProcessColumn?b._cy:(b._y<a._y?b._y+b._h:b._y);const railX=Number.isFinite(e._feedbackRailX)?e._feedbackRailX:Math.min(a._x,b._x)-58-Math.abs(offset);return`M ${startX} ${startY} L ${railX} ${startY} L ${railX} ${endY} L ${endX} ${endY}`;}if(Math.abs(sy-ty)<2||Math.abs(sx-tx)<2)return`M ${sx} ${sy} L ${tx} ${ty}`;if(p.axis==='vertical'){const midY=(sy+ty)/2+offset;return`M ${sx} ${sy} L ${sx} ${midY} L ${tx} ${midY} L ${tx} ${ty}`;}const midX=(sx+tx)/2+offset;return`M ${sx} ${sy} L ${midX} ${sy} L ${midX} ${ty} L ${tx} ${ty}`;}const dx=Math.max(40,Math.abs(tx-sx)*0.45);return`M ${sx} ${sy} C ${sx+dx+offset} ${sy}, ${tx-dx+offset} ${ty}, ${tx} ${ty}`;}",
    "function drawWorkflowGraph(el,nodes,edges,onNodeClick,onEdgeClick){nodes=(nodes||[]).map(n=>({...n}));edges=(edges||[]).map(e=>({...e}));onNodeClick=onNodeClick||selectWorkflowNode;onEdgeClick=onEdgeClick||((index)=>renderWorkflowEdge(index,edges));const opt={nodeW:180,colGap:250,rowGap:34,top:34,left:48};prepareWorkflowNodes(nodes);let h;if(config.graph_layout==='layered'){h=layoutWorkflowLayered(nodes,edges,opt);}else if(config.graph_layout==='swimlane'){h=layoutWorkflowSwimlane(nodes,edges,opt);}else if(config.graph_layout==='process'){h=layoutWorkflowProcess(nodes,edges,opt);}else{h=layoutWorkflowGrid(nodes,opt);}nodes.forEach(n=>{n._cy=n._y+n._h/2;});const maxRight=nodes.length?Math.max(...nodes.map(n=>n._x+opt.nodeW+opt.left)):820;const minLeft=nodes.length?Math.min(...nodes.map(n=>n._x)):0;const minEdgeX=edges.length?Math.min(...edges.map(e=>Math.min(Number.isFinite(e._feedbackRailX)?e._feedbackRailX:Infinity,Number.isFinite(e._branchRailX)?e._branchRailX:Infinity))):Infinity;const maxEdgeX=edges.length?Math.max(...edges.map(e=>Math.max(Number.isFinite(e._branchRailX)?e._branchRailX:-Infinity,Number.isFinite(e._feedbackRailX)?e._feedbackRailX:-Infinity))):-Infinity;const viewLeft=Math.min(0,minLeft-80,Number.isFinite(minEdgeX)?minEdgeX-40:0);const viewRight=Math.max(maxRight,Number.isFinite(maxEdgeX)?maxEdgeX+opt.left+40:0);const w=Math.max(820,viewRight-viewLeft);let svg=`<svg viewBox='${viewLeft} 0 ${w} ${h}' width='${w}' height='${h}' role='img' aria-label='Workflow graph'>`;svg+=`<defs><marker id='arrow' viewBox='0 0 10 10' refX='8' refY='5' markerWidth='6' markerHeight='6' orient='auto-start-reverse'><path d='M 0 0 L 10 5 L 0 10 z' fill='#6b7280'/></marker><marker id='arrow-branch' viewBox='0 0 10 10' refX='8' refY='5' markerWidth='6' markerHeight='6' orient='auto-start-reverse'><path d='M 0 0 L 10 5 L 0 10 z' fill='#B45309'/></marker></defs>`;if(config.graph_layout==='swimlane'){const lanes=[...new Set(nodes.map(n=>n._lane))];lanes.forEach(lane=>{const n=nodes.find(x=>x._lane===lane);if(n){svg+=`<rect x='${opt.left}' y='${n._laneY}' width='${w-opt.left*2}' height='${n._laneH}' rx='10' fill='${lanes.indexOf(lane)%2?'#f3efe5':'#faf7ef'}' stroke='#d7cebd'/><text x='${opt.left+12}' y='${n._laneY+20}' font-size='12' fill='#52606d'>${esc(lane)}</text>`;}});}edges.forEach((e,i)=>{const a=nodes.find(n=>n.id===e.from),b=nodes.find(n=>n.id===e.to);if(a&&b){const visual=edgeVisual(e);const label=edgeLabel(e);svg+=`<path data-edge-index='${i}' d='${edgePath(a,b,opt.nodeW,config.edge_style,i,e)}' fill='none' stroke='${visual.stroke}' stroke-width='${isBranchEdge(e)?2:1.5}' stroke-dasharray='${visual.dash}' marker-end='${visual.marker}' style='pointer-events:stroke;cursor:pointer'/>`;if(label){const pos=edgeLabelPosition(a,b,e);const text=esc(label);const labelW=Math.min(210,Math.max(44,text.length*6.8+16));svg+=`<g data-edge-index='${i}' style='cursor:pointer'><rect x='${pos.x-labelW/2}' y='${pos.y-15}' width='${labelW}' height='20' rx='4' fill='${visual.labelFill}' stroke='${visual.labelStroke}'/><text x='${pos.x}' y='${pos.y}' text-anchor='middle' font-size='11' fill='#374151'>${text}</text></g>`;}}});nodes.forEach(n=>{const tx=n._x+opt.nodeW/2;const visual=nodeVisual(n);const titleText=`${n.label} (${visual.label||''})`;const nested=hasNestedWorkflow(n);svg+=`<g tabindex='0' role='button' data-node-id='${esc(n.id)}'><title>${esc(titleText)}${nested?' - nested workflow':''}</title><rect x='${n._x}' y='${n._y}' width='${opt.nodeW}' height='${n._h}' rx='8' fill='${visual.fill}' stroke='${visual.stroke}'/>${nested?`<g aria-hidden='true'><rect x='${n._x+opt.nodeW-24}' y='${n._y+8}' width='16' height='16' rx='4' fill='${visual.stroke}' stroke='${visual.stroke}'/><path d='M ${n._x+opt.nodeW-20} ${n._y+14} L ${n._x+opt.nodeW-16} ${n._y+10} L ${n._x+opt.nodeW-12} ${n._y+14} L ${n._x+opt.nodeW-16} ${n._y+18} Z' fill='#fff'/></g>`:''}<text text-anchor='middle' font-size='12'>${svgTspans(n._lines,tx,n._y+28,15)}</text></g>`;});svg+='</svg>';el.innerHTML=`<div class='graph-scroll'>${svg}</div>`;el.querySelectorAll('[data-node-id]').forEach(x=>{x.onclick=()=>onNodeClick(x.getAttribute('data-node-id'));});el.querySelectorAll('[data-edge-index]').forEach(x=>{x.onclick=()=>onEdgeClick(Number(x.getAttribute('data-edge-index')));});}",
    "function reviewGraphVisual(n){const kind=String(n.kind||n.node_type||n.memory_type||'item');const palette={root:{fill:'#F3F4F6',stroke:'#374151'},context:{fill:'#DBEAFE',stroke:'#1D4ED8'},semantic:{fill:'#DCFCE7',stroke:'#15803D'},episodic:{fill:'#FEF3C7',stroke:'#B45309'},procedural:{fill:'#FCE7F3',stroke:'#BE185D'},knowledge_item:{fill:'#DBEAFE',stroke:'#1D4ED8'},graph_node:{fill:'#EDE9FE',stroke:'#6D28D9'},domain:{fill:'#F3E8FF',stroke:'#7E22CE'},type:{fill:'#ECFDF5',stroke:'#047857'}};return palette[kind]||{fill:'#F3F4F6',stroke:'#6B7280'};}",
    "function layoutReviewGraph(nodes,edges,opt){const byId=Object.fromEntries(nodes.map(n=>[n.id,n]));const indeg=Object.fromEntries(nodes.map(n=>[n.id,0]));edges.forEach(e=>{if(byId[e.from]&&byId[e.to])indeg[e.to]=(indeg[e.to]||0)+1;});const depth=Object.fromEntries(nodes.map(n=>[n.id,0]));const q=nodes.filter(n=>(indeg[n.id]||0)===0).map(n=>n.id);let guard=0;while(q.length&&guard++<nodes.length*nodes.length){const id=q.shift();edges.filter(e=>e.from===id&&byId[e.to]).forEach(e=>{depth[e.to]=Math.max(depth[e.to]||0,(depth[id]||0)+1);indeg[e.to]-=1;if(indeg[e.to]===0)q.push(e.to);});}const groups={};nodes.forEach((n,i)=>{n._lines=wrapSvgText(n.label||n.id,22);n._h=Math.max(48,24+n._lines.length*14);n._depth=depth[n.id]||0;if(!groups[n._depth])groups[n._depth]=[];groups[n._depth].push(n);});let maxBottom=0;Object.keys(groups).sort((a,b)=>Number(a)-Number(b)).forEach(k=>{groups[k].forEach((n,i)=>{n._x=opt.left+Number(k)*opt.colGap;n._y=opt.top+i*(n._h+opt.rowGap);n._cy=n._y+n._h/2;maxBottom=Math.max(maxBottom,n._y+n._h+opt.top);});});return Math.max(160,maxBottom);}",
    "function drawReviewGraph(el,nodes,edges,onNodeClick,onEdgeClick,title='Design graph'){nodes=(nodes||[]).map(n=>({...n}));edges=(edges||[]).map(e=>({...e}));if(!nodes.length){el.innerHTML='';return;}const opt={nodeW:170,colGap:230,rowGap:24,top:28,left:40};const h=layoutReviewGraph(nodes,edges,opt);const maxRight=Math.max(...nodes.map(n=>n._x+opt.nodeW+opt.left));const w=Math.max(640,maxRight);let svg=`<svg viewBox='0 0 ${w} ${h}' width='${w}' height='${h}' role='img' aria-label='${esc(title)}'>`;svg+=`<defs><marker id='arrow-review' viewBox='0 0 10 10' refX='8' refY='5' markerWidth='6' markerHeight='6' orient='auto-start-reverse'><path d='M 0 0 L 10 5 L 0 10 z' fill='#6b7280'/></marker></defs>`;edges.forEach((e,i)=>{const a=nodes.find(n=>n.id===e.from),b=nodes.find(n=>n.id===e.to);if(!a||!b)return;const sx=a._x+opt.nodeW,sy=a._cy,tx=b._x,ty=b._cy,mid=(sx+tx)/2;svg+=`<path data-review-edge-index='${i}' d='M ${sx} ${sy} C ${mid} ${sy}, ${mid} ${ty}, ${tx} ${ty}' fill='none' stroke='#6b7280' stroke-width='1.3' marker-end='url(#arrow-review)' style='pointer-events:stroke;cursor:pointer'/>`;if(e.relation){svg+=`<text x='${mid}' y='${(sy+ty)/2-5}' text-anchor='middle' font-size='10' fill='#52606d'>${esc(e.relation)}</text>`;}});nodes.forEach(n=>{const visual=reviewGraphVisual(n),tx=n._x+opt.nodeW/2;svg+=`<g tabindex='0' role='button' data-review-node-id='${esc(n.id)}'><title>${esc(n.id)}</title><rect x='${n._x}' y='${n._y}' width='${opt.nodeW}' height='${n._h}' rx='8' fill='${visual.fill}' stroke='${visual.stroke}'/><text text-anchor='middle' font-size='12'>${svgTspans(n._lines,tx,n._y+24,14)}</text></g>`;});svg+='</svg>';el.innerHTML=`<div class='graph-scroll'>${svg}</div>`;el.querySelectorAll('[data-review-node-id]').forEach(x=>{x.onclick=()=>onNodeClick&&onNodeClick(x.getAttribute('data-review-node-id'));});el.querySelectorAll('[data-review-edge-index]').forEach(x=>{x.onclick=()=>onEdgeClick&&onEdgeClick(Number(x.getAttribute('data-review-edge-index')));});}",
    "function memoryGraphData(fields){const nodes=[{id:'memory_schema',label:'Memory schema',kind:'root'}],edges=[];(fields||[]).forEach(f=>{nodes.push({id:f.id,label:f.label||f.id,kind:f.memory_type||'memory_field',field:f});edges.push({from:'memory_schema',to:f.id,relation:f.memory_type||'field'});});return{nodes,edges};}",
    "function knowledgeGraphData(items,graphNodes,graphEdges){if((graphNodes||[]).length){return{nodes:(graphNodes||[]).map(n=>({id:n.id,label:n.label||n.id,kind:'graph_node',node:n})),edges:(graphEdges||[]).map(e=>({from:e.from,to:e.to,relation:e.relation||e.relation_type||'relates_to',edge:e}))};}const nodes=[{id:'knowledge_spec',label:'Knowledge spec',kind:'root'}],edges=[];(items||[]).forEach(k=>{nodes.push({id:k.id,label:k.normalized_statement||k.raw_statement||k.id,kind:'knowledge_item',item:k});edges.push({from:'knowledge_spec',to:k.id,relation:k.type||'item'});if(k.domain){const domainId='domain::'+String(k.domain);if(!nodes.find(n=>n.id===domainId))nodes.push({id:domainId,label:k.domain,kind:'domain'});edges.push({from:k.id,to:domainId,relation:'domain'});}});return{nodes,edges};}",
    "function renderMemoryFieldDetail(f){const box=document.getElementById('node_detail');if(!box)return;box.innerHTML=`<div class='detail-box'><div class='id'>${esc(f.id)}</div><div class='label'>${esc(f.label)}</div><div class='detail-kv'><b>Memory type</b><span>${esc(val(f.memory_type))}</span><b>Persistence</b><span>${esc(val(f.persistence))}</span><b>Source</b><span>${esc(val(f.source))}</span><b>Description</b><span>${esc(val(f.description))}</span></div><h3>Schema</h3>${jsonBlock(f.schema||{})}<h3>Update policy</h3>${jsonBlock(f.update_policy||{})}</div>`;}",
    "function renderKnowledgeItemDetail(k){const box=document.getElementById('node_detail');if(!box)return;box.innerHTML=`<div class='detail-box'><div class='id'>${esc(k.id)}</div><div class='label'>${esc(k.type)}</div><div class='detail-kv'><b>Domain</b><span>${esc(val(k.domain))}</span><b>Confidence</b><span>${esc(val(k.confidence))}</span><b>Review</b><span>${esc(k.review&&k.review.status?k.review.status:'')}</span></div><h3>Normalized statement</h3><div class='small'>${esc(val(k.normalized_statement))}</div><h3>Raw statement</h3><div class='small'>${esc(val(k.raw_statement))}</div></div>`;}",
    "function renderGraphNodeDetail(n){const box=document.getElementById('node_detail');if(!box)return;box.innerHTML=`<div class='detail-box'><div class='id'>${esc(n.id)}</div><div class='label'>${esc(n.label)}</div><div class='detail-kv'><b>Node type</b><span>${esc(val(n.node_type))}</span><b>Memory type</b><span>${esc(val(n.memory_type))}</span><b>Review</b><span>${esc(n.review&&n.review.status?n.review.status:'')}</span></div><h3>Raw graph node</h3>${jsonBlock(n)}</div>`;}",
    "function renderGraphEdgeDetail(e){const box=document.getElementById('node_detail');if(!box)return;box.innerHTML=`<div class='detail-box'><div class='id'>${esc(e.from)} -> ${esc(e.to)}</div><div class='label'>${esc(val(e.relation)||val(e.relation_type)||'relates_to')}</div><div class='detail-kv'><b>From</b><span>${esc(e.from)}</span><b>To</b><span>${esc(e.to)}</span><b>Relation</b><span>${esc(val(e.relation))}</span><b>Relation type</b><span>${esc(val(e.relation_type))}</span></div><h3>Raw graph edge</h3>${jsonBlock(e)}</div>`;}",
    "function renderTaskPreview(parentId){const parent=workflowNodeById(parentId);const host=document.getElementById('task_preview_main');if(!host||!parent||!parent.nested_workflow||!parent.nested_workflow.nodes)return;currentTaskPreviewId=parentId;document.querySelectorAll('.task-tab').forEach(btn=>btn.classList.toggle('active',btn.getAttribute('data-task-id')===parentId));host.innerHTML=`<h3>${esc(parent.label)}</h3><div class='small'>${esc(parent.subworkflow_ref||'Embedded nested workflow')}</div><div class='graph'></div>`;drawWorkflowGraph(host.querySelector('.graph'),parent.nested_workflow.nodes||[],parent.nested_workflow.edges||[],nodeId=>renderNestedNodeDetail(parentId,nodeId),edgeIndex=>{const nested=parent.nested_workflow&&parent.nested_workflow.edges||[];const edge=workflowEdgeByIndex(edgeIndex,nested);if(!edge)return;renderEdgeDetailObject(edge,'Nested edge inside '+parentId,parent.nested_workflow.nodes||[]);selectTarget('workflow_edge',parentId+'::'+edge.from+'->'+edge.to,'workflow.nodes.'+parentId+'.nested_workflow.edges');});}",
    "function renderWorkflowLegend(){const host=document.getElementById('workflow-legend');if(!host)return;let items=[];if(nodeColorTheme()==='subsystems'){items=['rwm','pg','ae','la','iac'].map(key=>subsystemPalette[key]).concat([{fill:'#EEF2F7',stroke:'#7B8794',label:'Unlabeled'}]);}else{items=[{fill:'#FFF1D6',stroke:'#B45309',label:'Human gate'},{fill:'#E8F3EE',stroke:'#607466',label:'Deterministic automation'},{fill:'#E9E4FB',stroke:'#6D28D9',label:'External stochastic LLM'}];}host.innerHTML=items.map(item=>`<span class='workflow-legend-item'><span class='workflow-swatch' style='background:${item.fill};border-color:${item.stroke}'></span>${esc(item.label)}</span>`).join('');}",
    "function applyWorkflowTheme(){const nodes=data.workflow_graph.nodes||[],edges=data.workflow_graph.edges||[];if(currentWorkflowGraphEl)drawWorkflowGraph(currentWorkflowGraphEl,nodes,edges);renderWorkflowLegend();if(currentTaskPreviewId)renderTaskPreview(currentTaskPreviewId);}",
    "function renderTaskTabs(nodes){const tasks=(nodes||[]).filter(n=>n.nested_workflow&&n.nested_workflow.nodes);if(!tasks.length)return;const s=document.createElement('section');s.className='panel nested-wide';s.id='task_previews';s.innerHTML='<h2>Task previews</h2><div class=\"small\">Select a task label to preview its lower-level workflow in the main page.</div><div class=\"task-tabs\"></div><div id=\"task_preview_main\"></div>';main.appendChild(s);const tabs=s.querySelector('.task-tabs');tasks.forEach(n=>{const btn=document.createElement('button');btn.className='task-tab';btn.setAttribute('data-task-id',n.id);btn.textContent=n.label;btn.onclick=()=>{renderNodeDetail(n.id);renderTaskPreview(n.id);};tabs.appendChild(btn);});renderTaskPreview(tasks[0].id);}",
    "function renderWorkflow(){if(!config.include_workflow)return;const s=section('Workflow graph','workflow');const nodes=data.workflow_graph.nodes||[],edges=data.workflow_graph.edges||[];if(hasBackwardEdges(nodes,edges)&&config.graph_layout!=='process'){const note=document.createElement('div');note.className='notice';note.textContent='This workflow contains backward/loop edges. Use graph_layout = \"process\" for a clearer loop-aware review diagram.';s.appendChild(note);}const toolbar=document.createElement('div');toolbar.className='workflow-toolbar';toolbar.innerHTML=`<div class='small'>Graph nodes represent the reviewed task workflow, including external scripts and external LLM steps. Parent nodes with nested workflows inherit the most restrictive descendant category in the default theme.</div><div class='row-inline'><label for='workflow-theme-select'>Node colors</label><select id='workflow-theme-select'><option value='default'>Default</option><option value='subsystems'>Subsystems</option></select></div>`;s.appendChild(toolbar);const legend=document.createElement('div');legend.id='workflow-legend';legend.className='workflow-legend';s.appendChild(legend);const g=document.createElement('div');g.className='graph';g.id='workflow_graph_canvas';s.appendChild(g);currentWorkflowGraphEl=g;drawWorkflowGraph(g,nodes,edges);document.getElementById('workflow-theme-select').value=config.node_color_theme||'default';document.getElementById('workflow-theme-select').onchange=e=>{config.node_color_theme=e.target.value;applyWorkflowTheme();};renderWorkflowLegend();renderTaskTabs(nodes);}",
    "function renderKnowledge(){if(!config.include_knowledge)return;const items=data.narrative_knowledge.items||[],graphNodes=data.graph_knowledge.nodes||[],graphEdges=data.graph_knowledge.edges||[];if(!items.length&&!graphNodes.length&&!graphEdges.length)return;const s=section('Knowledge and graph knowledge','knowledge');const kg=knowledgeGraphData(items,graphNodes,graphEdges);if(kg.nodes.length){const graph=document.createElement('div');graph.className='graph';graph.id='knowledge_graph_canvas';s.appendChild(graph);drawReviewGraph(graph,kg.nodes,kg.edges,id=>{const node=kg.nodes.find(n=>n.id===id);if(!node)return;if(node.item){renderKnowledgeItemDetail(node.item);selectTarget('knowledge_item',node.item.id,'knowledge.items.'+node.item.id);}else if(node.node){renderGraphNodeDetail(node.node);selectTarget('graph_node',node.node.id,'graph.nodes.'+node.node.id);}else{selectTarget('narrative_knowledge',id,'knowledge');}},idx=>{const e=kg.edges[idx];if(!e)return;if(e.edge)renderGraphEdgeDetail(e.edge);selectTarget('graph_edge',e.from+'->'+e.to,'graph.edges');},graphNodes.length?'Graph knowledge':'Narrative knowledge map');}const grid=document.createElement('div');grid.className='grid';items.forEach(k=>{const c=document.createElement('div');c.className='card';c.innerHTML=`<button><div class='id'>${esc(k.id)}</div><div class='label'>${esc(k.type)}</div><div class='small'>${esc(k.normalized_statement||k.raw_statement)}</div></button>`;c.onclick=()=>{renderKnowledgeItemDetail(k);selectTarget('knowledge_item',k.id,'knowledge.items.'+k.id);};grid.appendChild(c);});graphNodes.forEach(n=>{const c=document.createElement('div');c.className='card';c.innerHTML=`<button><div class='id'>${esc(n.id)}</div><div class='label'>${esc(n.label)}</div><div class='small'>graph node: ${esc(n.node_type)}</div></button>`;c.onclick=()=>{renderGraphNodeDetail(n);selectTarget('graph_node',n.id,'graph.nodes.'+n.id);};grid.appendChild(c);});s.appendChild(grid);}",
    "function renderMemory(){if(!config.include_memory_schema)return;const fields=data.memory_schema.fields||[];const metaKeys=['state_spec','interface_spec','autonomy_spec'].filter(k=>data.metadata&&data.metadata[k]);if(!fields.length&&!metaKeys.length)return;const s=section('Memory, state, and interface schema','memory');if(fields.length){const mg=memoryGraphData(fields);const graph=document.createElement('div');graph.className='graph';graph.id='memory_schema_graph_canvas';s.appendChild(graph);drawReviewGraph(graph,mg.nodes,mg.edges,id=>{const f=fields.find(x=>x.id===id);if(f){renderMemoryFieldDetail(f);selectTarget('memory_schema',f.id,'memory.fields.'+f.id);}else{selectTarget('memory_schema',id,'memory');}},null,'Memory schema graph');const grid=document.createElement('div');grid.className='grid';fields.forEach(f=>{const c=document.createElement('div');c.className='card';c.innerHTML=`<button><div class='id'>${esc(f.id)}</div><div class='label'>${esc(f.label)}</div><div class='small'>${esc(f.memory_type)} | ${esc(f.persistence)}</div><div class='small'>${esc(f.description)}</div></button>`;c.onclick=()=>{renderMemoryFieldDetail(f);selectTarget('memory_schema',f.id,'memory.fields.'+f.id);};grid.appendChild(c);});s.appendChild(grid);}metaKeys.forEach(k=>{const pre=document.createElement('pre');pre.textContent=k+':\\n'+JSON.stringify(data.metadata[k],null,2);s.appendChild(pre);});}",
    "function renderFeedback(){if(!config.include_feedback_panel){panel.style.display='none';return;}const schema=data.feedback_schema;panel.innerHTML=`<h2>Detail inspector</h2><div id='node_detail' class='detail-box'><div class='small'>Click a workflow node or edge to inspect its details.</div></div><div class='feedback-section-gap'></div><h2>Structured feedback</h2><div class='row'><label>Target</label><select id='fb_target'>${schema.targets.map(t=>`<option>${esc(t)}</option>`).join('')}</select></div><div class='row'><label>Target id</label><input id='fb_target_id'></div><div class='row'><label>Field</label><input id='fb_field' value='workflow_node'></div><div class='row'><label>Issue type</label><select id='fb_issue_type'>${schema.issue_types.map(t=>`<option>${esc(t)}</option>`).join('')}</select></div><div class='row'><label>Issue</label><textarea id='fb_issue'></textarea></div><div class='row'><label>Suggestion</label><textarea id='fb_suggestion'></textarea></div><div class='row'><label>Severity</label><select id='fb_severity'>${schema.severities.map(t=>`<option>${esc(t)}</option>`).join('')}</select></div><div class='btns'><button class='btn' id='addFb'>Add feedback</button><button class='btn secondary' id='copyFb'>Copy JSON</button><button class='btn secondary' id='downloadFb'>Download JSON</button></div><h3>Feedback JSON</h3><pre id='fb_json'>{\"feedback\":[]}</pre><div id='fb_list'></div>`;document.getElementById('addFb').onclick=addFeedback;document.getElementById('copyFb').onclick=()=>navigator.clipboard&&navigator.clipboard.writeText(document.getElementById('fb_json').textContent);document.getElementById('downloadFb').onclick=downloadFeedback;}",
    "function setSideWidth(px){const min=300,max=Math.max(320,wrap.getBoundingClientRect().width-320-10);const clamped=Math.min(max,Math.max(min,Math.round(px)));wrap.style.setProperty('--side-width',clamped+'px');try{localStorage.setItem('agentr-review-side-width',String(clamped));}catch(e){}return clamped;}",
    "function initSplit(){if(!wrap||!splitter)return;try{const saved=Number(localStorage.getItem('agentr-review-side-width'));if(Number.isFinite(saved)&&saved>0)setSideWidth(saved);}catch(e){}splitter.addEventListener('pointerdown',e=>{if(e.button!==0)return;e.preventDefault();splitter.classList.add('dragging');const move=ev=>{setSideWidth(wrap.getBoundingClientRect().right-ev.clientX);};const up=()=>{splitter.classList.remove('dragging');window.removeEventListener('pointermove',move);window.removeEventListener('pointerup',up);};window.addEventListener('pointermove',move);window.addEventListener('pointerup',up);});window.addEventListener('resize',()=>{const current=parseFloat(getComputedStyle(wrap).getPropertyValue('--side-width'));if(Number.isFinite(current)&&current>0)setSideWidth(current);});}",
    "function addFeedback(){const item={id:'fb_'+String(feedback.length+1).padStart(3,'0'),target:fb_target.value,target_id:fb_target_id.value,item_id:fb_target_id.value,field:fb_field.value,issue_type:fb_issue_type.value,issue:fb_issue.value,suggestion:fb_suggestion.value,severity:fb_severity.value,status:'open',source:'human',created_at:new Date().toISOString(),metadata:{review_id:data.review_id}};feedback.push(item);fb_issue.value='';fb_suggestion.value='';renderFeedbackList();}",
    "function renderFeedbackList(){const txt=JSON.stringify({feedback},null,2);document.getElementById('fb_json').textContent=txt;const list=document.getElementById('fb_list');list.innerHTML='';feedback.forEach((f,i)=>{const d=document.createElement('div');d.className='feedback-item';d.innerHTML=`<b>${esc(f.target)}</b> ${esc(f.target_id)}<br>${esc(f.issue)}<br><button class='btn secondary' data-i='${i}'>Delete</button>`;d.querySelector('button').onclick=()=>{feedback.splice(i,1);renderFeedbackList();};list.appendChild(d);});}",
    "function downloadFeedback(){const blob=new Blob([JSON.stringify({feedback},null,2)],{type:'application/json'});const a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download=(data.review_id||'agentr_design_feedback')+'.json';a.click();URL.revokeObjectURL(a.href);}",
    "renderWorkflow();renderKnowledge();renderMemory();renderFeedback();initSplit();const firstNode=(data.workflow_graph.nodes||[])[0];if(firstNode)renderNodeDetail(firstNode.id);",
    "</script>",
    "</body>",
    "</html>",
    sep = "\n"
  )
}

#' Export standalone design-review HTML
#'
#' @param x A [`DesignReviewSpec`] or any input accepted by
#'   [build_design_review_data()].
#' @param path Output HTML path.
#' @param ... Arguments passed to [design_review_html()].
#'
#' @return Invisibly returns the normalized output path.
#' @export
export_design_review_html <- function(x, path, ...) {
  html <- design_review_html(x, ...)
  writeLines(html, path, useBytes = TRUE)
  invisible(normalizePath(path, mustWork = FALSE))
}
